Hi

Here's my schema and a test case for it:

```
import unittest

from voluptuous import Schema, Required, Any, MultipleInvalid


schema = Schema({
    Required('inview', default=False): Any(bool, None),
    Required('mute', default=True): Any(bool, None),
})


class TestSchemaValidation(unittest.TestCase):

    def setUp(self):
        self.data = {
            'inview': True,
            'mute': False
        }

    def _assertExceptionHasText(self, text):
        try:
            schema(self.data)
            raise AssertionError('MultipleInvalid not raised')
        except MultipleInvalid as e:
            self.assertIn(text, str(e))

    def test_inview(self):
        # Test knows how to deal with None and has default value.
        self.data['inview'] = None
        self.assertFalse(schema(self.data)['inview'])
        del self.data['inview']
        self.assertFalse(schema(self.data)['inview'])

    def test_mute(self):
        # Test knows how to deal with None and has default value.
        self.data['mute'] = None
        self.assertTrue(schema(self.data)['mute'])
        del self.data['mute']
        self.assertTrue(schema(self.data)['mute'])


if __name__ == '__main__':
    unittest.main()

```

I might be doing something wrong here (like allowing bool field to be None), but either way the behaviour is inconsistent depending on whether the field is True or False

